// Determine which follow-up to send based on elapsed hours since last_message_at.
// Slot 1 → 24h, Slot 2 → 48h, Slot 3 → 72h.
// A conversation is eligible if:
//   - It's past the threshold for its NEXT follow-up (follow_up_count + 1)
//   - It hasn't already been sent a follow-up in that slot

const SLOTS = [24, 48, 72]; // hours for follow-up 1, 2, 3

const now = Date.now();
const eligible = [];

for (const item of $input.all()) {
  const conv = item.json;
  const sentCount = conv.follow_up_count || 0;
  if (sentCount >= 3) continue;

  const lastAt = conv.follow_up_sent_at || conv.last_message_at;
  if (!lastAt) continue;

  const elapsedHours = (now - new Date(lastAt).getTime()) / (1000 * 60 * 60);
  const nextSlot = SLOTS[sentCount]; // 24 for first, 48 for second, 72 for third

  if (elapsedHours >= nextSlot) {
    eligible.push({ json: { ...conv, next_followup_number: sentCount + 1 } });
  }
}

return eligible;

const conv = $input.item.json;
const n = conv.next_followup_number;

const texts = {
  1: 'Hola, ¿pudiste ver la información que te enviamos? Estamos aquí para ayudarte.',
  2: 'Hola de nuevo! ¿Tienes alguna pregunta sobre nuestros productos? Con gusto te atendemos.',
  3: 'Hola! Es nuestro último mensaje por ahora. Si en algún momento te interesa saber más, escríbenos. 😊',
};

return [{ json: { ...conv, followup_text: texts[n] || texts[1] } }];
